import play.api.mvc._

class FileController extends Controller {
  def serveFile(filename: String) = Action {
    val path = s"uploads/$filename"
    try {
      val source = scala.io.Source.fromFile(path)
      Ok(source.getLines.mkString).as("text/plain")
    } catch {
      case _: java.io.FileNotFoundException => NotFound(s"File not found: $path")
      case e: Exception => InternalServerError(s"Error reading file: $e")
    }
  }
}